102	
103	        const hierarchyRoot = hierarchy(data)
104	            .sort((a, b) => ascending(a.data.name, b.data.name));
105	
106	        const maxDepth = hierarchyRoot.height;
107	
108	        /*
109	         * Pass 1 — lay out with outerRadius = 1 so every node's x is its
110	         * final angle in [0, 2π] and y is its normalised depth (depth/maxDepth).
111	         * The x-coordinates are independent of the radius and will not change
112	         * when we re-scale y in Pass 2.
113	         */
