116	            .separation((a, b) => (a.parent === b.parent ? 1 : 2) / Math.max(1, a.depth));
117	
118	        const root = treeLayout(hierarchyRoot);
119	
120	        /*
121	         * Pass 2 — derive the smallest outer radius that prevents mugshot
122	         * overlap at every depth, floored at half the SVG width so sparse
123	         * trees still fill the space. See familyTreeRadius.ts for the maths.
124	         *
125	         * computeTreeRadius returns Infinity when two nodes share an angle
126	         * (unsatisfiable constraint). Cap at 4× the container width so that
127	         * the subsequent y-scaling never produces NaN (Infinity × 0).
128	         */
129	        const radius = Math.min(
130	            computeTreeRadius(
131	                groups(root.descendants(), (d) => d.depth),
132	                maxDepth,
133	                Math.max(0, (width - RADIUS_FLOOR_PADDING) / 2),
134	                MUGSHOT_SIZE,
135	                MUGSHOT_GAP,
