1	'use client';
2	
3	import {
4	    Anchor,
5	    Box,
6	    Group,
7	    Image,
8	    Popover,
9	    ScrollArea,
10	    Stack,
11	    Text,
12	} from '@mantine/core';
13	import { json } from 'd3-fetch';
14	import { geoMercator, geoPath } from 'd3-geo';
15	import { select } from 'd3-selection';
16	import { useCallback, useEffect, useMemo, useRef, useState } from 'react';
17	import * as topojson from 'topojson-client';
18	import type { GeometryCollection, Topology } from 'topojson-specification';
19	
20	import { CountrySupporterWithPlayerDataType } from '@/types';
21	
22	/**
23	 * Mapping from database country names to their corresponding TopoJSON atlas
24	 * names where they differ. Multiple DB names may map to the same atlas entry
25	 * (e.g. the four UK home nations all map to "United Kingdom").
26	 */
27	const COUNTRY_NAME_MAP: Record<string, string> = {
28	    'England': 'United Kingdom',
29	    'Northern Ireland': 'United Kingdom',
30	    'Scotland': 'United Kingdom',
31	    'Wales': 'United Kingdom',
32	    'Russian Federation': 'Russia',
33	    'Bosnia and Herzegovina': 'Bosnia and Herz.',
34	    'Central African Republic': 'Central African Rep.',
35	    'Dominican Republic': 'Dominican Rep.',
36	    'Equatorial Guinea': 'Eq. Guinea',
37	    'Swaziland': 'eSwatini',
38	    'United States': 'United States of America',
39	};
40	
41	/**
42	 * Properties for the {@link PlayerCountryMap} component.
43	 */
44	export interface Props {
45	    /** Array of country supporter entries with player data for highlighting and hover. */
46	    countries: CountrySupporterWithPlayerDataType[];
47	    /** Width of the SVG viewport in pixels. */
48	    width?: number;
49	    /** Height of the SVG viewport in pixels. */
50	    height?: number;
51	}
52	
53	/** Shape of properties on each country feature in the TopoJSON atlas. */
54	interface CountryProperties {
55	    name: string;
56	}
57	
58	/** Fill colour applied to highlighted (supported) countries. */
59	const HIGHLIGHT_FILL = '#228be6';
60	/** Fill colour for countries that are not highlighted. */
61	const DEFAULT_FILL = '#ccc';
62	/** Stroke colour for country borders. */
63	const STROKE_COLOUR = '#fff';
64	/** Stroke width for country borders. */
65	const STROKE_WIDTH = 0.5;
66	/** Maximum height of the scrollable player list inside the hover popover. */
67	const POPOVER_MAX_HEIGHT = 200;
68	/** Size of mugshot thumbnails in the hover popover. */
69	const MUGSHOT_SIZE = 32;
70	/** Delay in ms before closing the popover after mouse leaves a country path. */
71	const CLOSE_DELAY_MS = 200;
72	
73	/**
74	 * Resolves a database country name to its TopoJSON atlas equivalent.
75	 * Returns the mapped name if one exists, or the original name otherwise.
76	 */
77	const toAtlasName = (dbName: string): string =>
78	    COUNTRY_NAME_MAP[dbName] ?? dbName;
79	
80	/**
81	 * A D3-powered world map that highlights countries supported by players and
82	 * shows player mugshots in a popover on hover.
83	 *
84	 * Renders all countries from a TopoJSON world atlas and fills those whose
85	 * names match the supplied supporter entries with an accent colour. When a
86	 * highlighted country is hovered, a popover displays the mugshot and name of
87	 * each supporting player, grouped by their database country name (useful
88	 * when multiple nations share one atlas polygon, e.g. the four UK home
89	 * nations). For countries with many supporters the list is scrollable.
90	 *
91	 * Based on the approach described at
92	 * {@link http://www.d3noob.org/2013/03/a-simple-d3js-map-explained.html}.
93	 */
94	export const PlayerCountryMap = ({
95	    countries,
96	    width = 960,
97	    height = 500,
98	}: Props) => {
99	    const svgRef = useRef<SVGSVGElement>(null);
100	    /** Projected centroids for each highlighted atlas country. */
101	    const centroidsRef = useRef<Map<string, { x: number; y: number }>>(new Map());
102	    /** Timer handle for the delayed popover close. */
103	    const closeTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
104	    /** Whether the mouse is currently inside the popover dropdown. */
105	    const dropdownHoveredRef = useRef(false);
106	    const [popoverOpen, setPopoverOpen] = useState(false);
107	    const [popoverPos, setPopoverPos] = useState<{ x: number; y: number }>({ x: 0, y: 0 });
108	    const [hoveredCountry, setHoveredCountry] = useState<string | null>(null);
109	
110	    /**
111	     * Builds a lookup from lower-cased atlas country name to an array of
112	     * supporters. Multiple DB country names that share the same atlas name
113	     * are grouped together.
114	     */
115	    const supportersByAtlasName = useMemo(() => {
116	        const map = new Map<string, CountrySupporterWithPlayerDataType[]>();
117	        for (const cs of countries) {
118	            const key = toAtlasName(cs.country.name).toLowerCase();
119	            const arr = map.get(key) ?? [];
120	            arr.push(cs);
121	            map.set(key, arr);
122	        }
123	        return map;
124	    }, [countries]);
125	
126	    /**
127	     * Returns the supporters for the currently hovered country, grouped by
128	     * their original database country name for display purposes.
129	     */
130	    const hoveredGroups = useMemo(() => {
131	        if (!hoveredCountry) return [];
132	        /* v8 ignore next -- only countries in supportersByAtlasName trigger hover; get() always returns an array */
133	        const supporters = supportersByAtlasName.get(hoveredCountry) ?? [];
134	        const grouped = new Map<string, CountrySupporterWithPlayerDataType[]>();
135	        for (const s of supporters) {
136	            const key = s.country.name;
137	            const arr = grouped.get(key) ?? [];
138	            arr.push(s);
139	            grouped.set(key, arr);
140	        }
141	        return Array.from(grouped.entries());
142	    }, [hoveredCountry, supportersByAtlasName]);
143	
144	    /** Cancels any pending delayed close. */
145	    const cancelClose = useCallback(() => {
146	        if (closeTimerRef.current) {
147	            clearTimeout(closeTimerRef.current);
148	            closeTimerRef.current = null;
149	        }
150	    }, []);
151	
152	    /** Schedules a delayed popover close unless the dropdown is hovered. */
153	    const scheduleClose = useCallback(() => {
154	        cancelClose();
155	        closeTimerRef.current = setTimeout(() => {
156	            if (!dropdownHoveredRef.current) {
157	                setPopoverOpen(false);
158	                setHoveredCountry(null);
159	            }
160	        }, CLOSE_DELAY_MS);
161	    }, [cancelClose]);
162	
163	    /**
164	     * Handles mouse-enter on a highlighted country path. Anchors the popover
165	     * to the country's projected centroid for a stable position.
166	     */
167	    const handleMouseEnter = useCallback(
168	        (atlasName: string) => {
169	            cancelClose();
170	            const lowerName = atlasName.toLowerCase();
171	            const centroid = centroidsRef.current.get(lowerName);
172	            /* v8 ignore next -- centroid is always pre-computed before a D3 mouseenter can fire */
173	            if (centroid) {
174	                setPopoverPos(centroid);
175	            }
176	            setHoveredCountry(lowerName);
177	            setPopoverOpen(true);
178	        },
179	        [cancelClose],
180	    );
181	
182	    /** Handles mouse-leave on a highlighted country path. */
183	    const handleMouseLeave = useCallback(() => {
184	        scheduleClose();
185	    }, [scheduleClose]);
186	
187	    useEffect(() => {
188	        if (!svgRef.current) return;
189	
190	        const svg = select(svgRef.current);
191	        svg.selectAll('*').remove();
192	
193	        const projection = geoMercator()
194	            .center([0, 20])
195	            .scale(width / 6.5)
196	            .translate([width / 2, height / 2]);
197	
198	        const path = geoPath().projection(projection);
199	
200	        const g = svg.append('g');
201	
202	        const supportedNames = new Set(supportersByAtlasName.keys());
203	
204	        void json<Topology>('/countries-110m.json').then((topology) => {
205	            if (!topology) return undefined;
206	
207	            const geojson = topojson.feature(
208	                topology,
209	                topology.objects.countries as GeometryCollection,
210	            );
211	
212	            type CountryFeature = GeoJSON.Feature<GeoJSON.Geometry, CountryProperties>;
213	            const features = geojson.features as CountryFeature[];
214	
