1	'use client';
2	
3	import {
4	    Box,
5	    Button,
6	    Stack,
7	    Text,
8	    Textarea,
9	    TextInput,
10	    Title,
11	} from '@mantine/core';
12	import { useForm } from '@mantine/form';
13	import { notifications } from '@mantine/notifications';
14	import { IconAlertTriangle, IconCheck } from '@tabler/icons-react';
15	import { zod4Resolver } from 'mantine-form-zod-resolver';
16	import { usePathname, useRouter, useSearchParams } from 'next/navigation';
17	import { useEffect } from 'react';
18	
19	import { EmailInput } from '@/components/EmailInput/EmailInput';
20	import { config } from '@/lib/config';
21	import { toPublicMessage } from '@/lib/errors';
22	import { captureUnexpectedError } from '@/lib/observability/sentry';
23	import {
24	    EnquiryInput,
25	    EnquirySchema,
26	    SendEnquiryProxy,
27	} from '@/types/actions/SendEnquiry';
28	
29	export interface Props {
30	    redirectUrl: string;
31	    onSendEnquiry: SendEnquiryProxy;
32	}
33	
34	export const EnquiryForm = ({ redirectUrl, onSendEnquiry }: Props) => {
35	    const router = useRouter();
36	    const pathname = usePathname();
37	    const searchParams = useSearchParams();
38	
39	    const form = useForm<EnquiryInput>({
40	        initialValues: {
41	            name: '',
42	            email: '',
43	            message: '',
44	        },
45	        validate: zod4Resolver(EnquirySchema),
46	        validateInputOnBlur: true,
47	    });
48	
49	    useEffect(() => {
50	        const enquiryStatus = searchParams.get('enquiry');
51	        const errorMessage = searchParams.get('error');
52	
53	        if (!enquiryStatus) {
54	            return;
55	        }
56	
57	        if (enquiryStatus === 'verified') {
58	            notifications.show({
59	                color: 'teal',
60	                title: 'Email verified',
61	                message: 'Thanks! Your enquiry has been delivered.',
62	                icon: <IconCheck size={config.notificationIconSize} />,
63	            });
64	        }
65	
66	        if (enquiryStatus === 'error') {
67	            notifications.show({
68	                color: 'red',
69	                title: 'Verification failed',
70	                message: errorMessage ?? 'We could not verify your email.',
71	                icon: <IconAlertTriangle size={config.notificationIconSize} />,
72	            });
73	        }
74	
75	        const updatedParams = new URLSearchParams(searchParams.toString());
76	        updatedParams.delete('enquiry');
77	        updatedParams.delete('error');
78	        const query = updatedParams.toString();
79	        router.replace(query ? `${pathname}?${query}` : pathname);
80	    }, [pathname, router, searchParams]);
81	
82	    const handleSubmit = async (values: EnquiryInput) => {
83	        const id = notifications.show({
84	            loading: true,
85	            title: 'Sending enquiry',
86	            message: 'Sending your message...',
87	            autoClose: false,
88	            withCloseButton: false,
89	        });
90	
91	        try {
92	            await onSendEnquiry(values, redirectUrl);
93	            form.reset();
94	
95	            notifications.update({
96	                id,
97	                color: 'teal',
98	                title: 'Confirm your email',
99	                message: 'Check your inbox and verify your email to deliver the message.',
100	                icon: <IconCheck size={config.notificationIconSize} />,
101	                loading: false,
102	                autoClose: config.notificationAutoClose,
103	            });
104	        } catch (error) {
105	            captureUnexpectedError(error, {
106	                layer: 'client',
107	                component: 'EnquiryForm',
108	                action: 'sendEnquiry',
109	                route: '/footy/contact',
110	                extra: {
111	                    redirectUrl,
112	                },
113	            });
114	            const message = toPublicMessage(error, 'Unable to send your message.');
115	            notifications.update({
116	                id,
117	                color: 'red',
118	                title: 'Error',
119	                message,
120	                icon: <IconAlertTriangle size={config.notificationIconSize} />,
121	                loading: false,
122	                autoClose: false,
123	                withCloseButton: true,
124	            });
125	        }
126	    };
127	
128	    return (
129	        <Box
130	            maw={520}
131	            component="form"
132	            onSubmit={form.onSubmit(handleSubmit)}
